// pages/SearchResults.js
import React, { useState, useEffect } from 'react';
import { useLocation, useNavigate } from 'react-router-dom';
import { FaSearch, FaBook, FaFileAlt, FaHistory, FaArrowLeft } from 'react-icons/fa';
import './SearchResults.css';

const SearchResults = () => {
  const location = useLocation();
  const navigate = useNavigate();
  const query = new URLSearchParams(location.search).get('q') || '';
  
  const [results, setResults] = useState([]);
  const [loading, setLoading] = useState(true);
  const [activeFilter, setActiveFilter] = useState('all');

  useEffect(() => {
    if (query) {
      fetchSearchResults(query);
    }
  }, [query]);

  const fetchSearchResults = (searchQuery) => {
    setLoading(true);
    
    // Mock data - Replace with your actual API
    const mockResults = [
      { id: 1, type: 'course', title: 'BCA', description: 'Bachelor of Computer Applications', icon: '📱', path: '/course/2' },
      { id: 2, type: 'subject', title: 'Programming in C', description: 'BCA Semester 1 Subject', icon: '💻', path: '/course/2/year/1/sem/1' },
      { id: 3, type: 'notes', title: 'C Programming Notes', description: 'Complete notes with examples', icon: '📝', path: '/materials/101' },
      { id: 4, type: 'pyq', title: 'BCA PYQs 2023', description: 'Previous year question papers', icon: '📄', path: '/pyqs/2023' },
      { id: 5, type: 'course', title: 'B.Tech', description: 'Bachelor of Technology', icon: '💻', path: '/course/1' },
      { id: 6, type: 'subject', title: 'Data Structures', description: 'B.Tech Semester 3 Subject', icon: '📚', path: '/course/1/year/2/sem/3' },
    ];

    // Filter results based on query
    const filteredResults = mockResults.filter(item =>
      item.title.toLowerCase().includes(searchQuery.toLowerCase()) ||
      item.description.toLowerCase().includes(searchQuery.toLowerCase())
    );

    setTimeout(() => {
      setResults(filteredResults);
      setLoading(false);
    }, 500);
  };

  const filteredResults = activeFilter === 'all' 
    ? results 
    : results.filter(item => item.type === activeFilter);

  return (
    <div className="search-results-container">
      {/* Header */}
      <div className="search-header">
        <button className="back-btn" onClick={() => navigate(-1)}>
          <FaArrowLeft /> Back
        </button>
        
        <div className="search-query">
          <h1>
            <FaSearch /> Search Results
          </h1>
          <p className="query-text">"{query}"</p>
          <p className="result-count">{results.length} results found</p>
        </div>
      </div>

      {/* Filters */}
      <div className="filters">
        <button 
          className={`filter-btn ${activeFilter === 'all' ? 'active' : ''}`}
          onClick={() => setActiveFilter('all')}
        >
          All
        </button>
        <button 
          className={`filter-btn ${activeFilter === 'course' ? 'active' : ''}`}
          onClick={() => setActiveFilter('course')}
        >
          <FaBook /> Courses
        </button>
        <button 
          className={`filter-btn ${activeFilter === 'subject' ? 'active' : ''}`}
          onClick={() => setActiveFilter('subject')}
        >
          📚 Subjects
        </button>
        <button 
          className={`filter-btn ${activeFilter === 'notes' ? 'active' : ''}`}
          onClick={() => setActiveFilter('notes')}
        >
          <FaFileAlt /> Notes
        </button>
        <button 
          className={`filter-btn ${activeFilter === 'pyq' ? 'active' : ''}`}
          onClick={() => setActiveFilter('pyq')}
        >
          <FaHistory /> PYQs
        </button>
      </div>

      {/* Results */}
      <div className="results-section">
        {loading ? (
          <div className="loading">
            <div className="spinner"></div>
            <p>Searching for "{query}"...</p>
          </div>
        ) : filteredResults.length > 0 ? (
          <div className="results-grid">
            {filteredResults.map((item) => (
              <div 
                key={item.id} 
                className="result-card"
                onClick={() => navigate(item.path)}
              >
                <div className="result-icon">{item.icon}</div>
                <div className="result-content">
                  <h3>{item.title}</h3>
                  <p className="result-desc">{item.description}</p>
                  <span className={`result-type ${item.type}`}>
                    {item.type.charAt(0).toUpperCase() + item.type.slice(1)}
                  </span>
                </div>
              </div>
            ))}
          </div>
        ) : (
          <div className="no-results">
            <FaSearch className="no-results-icon" />
            <h3>No results found for "{query}"</h3>
            <p>Try searching with different keywords</p>
            <button className="search-again-btn" onClick={() => navigate('/')}>
              Search Again
            </button>
          </div>
        )}
      </div>
    </div>
  );
};

export default SearchResults;
